update project_version
set index_status = 'INDEXING', index_started_at = now(), index_message = null
where id = #{id}

update project_version
set index_status = 'SUCCESS', indexed_at = now(), index_message = 'index completed'
where id = #{id}

update project_version
set index_status = 'FAILED', index_message = #{message}
where id = #{id}

update project_version
set index_message = #{message}
where id = #{id}

update project_version
set source_path = #{sourcePath}
where id = #{id}
